#!/bin/bash
echo "🔥 กำลังติดตั้ง CHAIYA V2RAY PRO MAX v8..."
export DEBIAN_FRONTEND=noninteractive

systemctl stop unattended-upgrades 2>/dev/null; pkill -f needrestart 2>/dev/null
rm -f /var/lib/dpkg/lock* /var/cache/apt/archives/lock 2>/dev/null
dpkg --configure -a 2>/dev/null

apt-get update -y -qq
apt-get install -y -qq curl wget python3 bc qrencode ufw nginx certbot python3-certbot-nginx python3-pip fail2ban sqlite3 2>/dev/null || true

systemctl stop apache2 2>/dev/null; systemctl disable apache2 2>/dev/null
systemctl stop xray 2>/dev/null; systemctl disable xray 2>/dev/null
rm -f /etc/systemd/system/xray.service /usr/local/bin/xray
rm -rf /usr/local/etc/xray /var/log/xray
systemctl daemon-reload 2>/dev/null

mkdir -p /etc/chaiya /var/www/chaiya/config /var/log/nginx
touch /etc/chaiya/vless.db /etc/chaiya/banned.db /etc/chaiya/iplog.db /etc/chaiya/datalimit.conf

ufw --force enable
ufw allow 22/tcp; ufw allow 80/tcp; ufw allow 443/tcp
ufw allow 8080/tcp; ufw allow 8880/tcp; ufw allow 2053/tcp

pip3 install bcrypt --break-system-packages -q 2>/dev/null

# nginx config (generic)
printf "%s" "" | base64 -d > /etc/nginx/sites-available/chaiya
ln -sf /etc/nginx/sites-available/chaiya /etc/nginx/sites-enabled/chaiya
rm -f /etc/nginx/sites-enabled/default
nginx -t && systemctl enable nginx && systemctl restart nginx

echo "✅ ติดตั้ง chaiya..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya
chmod +x /usr/local/bin/chaiya

echo "✅ ติดตั้ง chaiya-setup-xui..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-setup-xui
chmod +x /usr/local/bin/chaiya-setup-xui

echo "✅ ติดตั้ง chaiya-autoblock..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-autoblock
chmod +x /usr/local/bin/chaiya-autoblock

echo "✅ ติดตั้ง chaiya-bughost..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-bughost
chmod +x /usr/local/bin/chaiya-bughost

echo "✅ ติดตั้ง chaiya-cpukiller..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-cpukiller
chmod +x /usr/local/bin/chaiya-cpukiller

echo "✅ ติดตั้ง chaiya-delete-user..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-delete-user
chmod +x /usr/local/bin/chaiya-delete-user

echo "✅ ติดตั้ง chaiya-gen-page..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-gen-page
chmod +x /usr/local/bin/chaiya-gen-page

echo "✅ ติดตั้ง chaiya-manage-user..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-manage-user
chmod +x /usr/local/bin/chaiya-manage-user

echo "✅ ติดตั้ง chaiya-online..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-online
chmod +x /usr/local/bin/chaiya-online

echo "✅ ติดตั้ง chaiya-reboot-menu..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-reboot-menu
chmod +x /usr/local/bin/chaiya-reboot-menu

echo "✅ ติดตั้ง chaiya-show-accounts..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-show-accounts
chmod +x /usr/local/bin/chaiya-show-accounts

echo "✅ ติดตั้ง chaiya-user-manager..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-user-manager
chmod +x /usr/local/bin/chaiya-user-manager

echo "✅ ติดตั้ง chaiya-iplimit..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-iplimit
chmod +x /usr/local/bin/chaiya-iplimit

echo "✅ ติดตั้ง chaiya-datalimit..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-datalimit
chmod +x /usr/local/bin/chaiya-datalimit

echo "✅ ติดตั้ง chaiya-splash..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-splash
chmod +x /usr/local/bin/chaiya-splash

# cron
(crontab -l 2>/dev/null | grep -v chaiya-iplimit; echo "*/5 * * * * python3 /usr/local/bin/chaiya-iplimit >> /var/log/chaiya-iplimit.log 2>&1") | crontab -
(crontab -l 2>/dev/null | grep -v chaiya-datalimit; echo "*/5 * * * * python3 /usr/local/bin/chaiya-datalimit >> /var/log/chaiya-datalimit.log 2>&1") | crontab -


echo "✅ ติดตั้ง chaiya-sshws..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-sshws
chmod +x /usr/local/bin/chaiya-sshws

echo "✅ ติดตั้ง chaiya-sshws-api..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-sshws-api
chmod +x /usr/local/bin/chaiya-sshws-api

echo "✅ ติดตั้ง chaiya-sshws-nginx-setup..."
printf "%s" "" | base64 -d > /usr/local/bin/chaiya-sshws-nginx-setup
chmod +x /usr/local/bin/chaiya-sshws-nginx-setup

echo "✅ ติดตั้ง sshws.html..."
printf "%s" "" | base64 -d > /var/www/chaiya/sshws.html

echo ""
echo "======================================"
echo "✅ ติดตั้ง CHAIYA V2RAY PRO MAX เสร็จ!"
echo "👉 พิมพ์: chaiya เพื่อเปิดเมนู"
echo "🔥 กดเมนู 1 เพื่อติดตั้ง 3x-ui ก่อนครับ"
echo "======================================"
